export const getProductsByCategory = (catId) => PRODUCTS.filter(p => p.cat === catId);
export const getProductById = (id) => PRODUCTS.find(p => p.id === id);
export const getCategoryById = (catId) => CATEGORIES.find(c => c.id === catId);
export const getFeaturedProducts = () => PRODUCTS.filter(p => p.badge);
export const getNewArrivals = () => PRODUCTS.filter(p => p.badge === 'New');
